SELECT strategy_name, description, strategy_type, strategy_category, created_at, updated_at, created_by, updated_by
FROM strategies
WHERE strategy_id = 1;

SELECT strategy_name
FROM strategies
WHERE profit_potential = 1;

SELECT profit_or_loss 
FROM strategy_details 
WHERE strategy_id = 1;

SELECT SUM(profit_or_loss) AS Total_Profit_Or_Loss
FROM strategy_details
WHERE strategy_id = 1;

SELECT strategy_name 
FROM strategies 
WHERE strategy_id = 1;

SELECT *
FROM strategies
WHERE risk_level > (SELECT AVG(risk_level) FROM strategies);

SELECT strategies.strategy_name, strategy_details.underlying_asset
FROM strategies
INNER JOIN strategy_details ON strategies.strategy_id = strategy_details.strategy_id;

SELECT strategy_id, SUM(profit_or_loss) AS total_profit_or_loss
FROM strategy_details
GROUP BY strategy_id;
